//! Sequential phase orchestration — `forge run` and `forge phase <N>`.

use anyhow::Result;
use std::path::PathBuf;
use tracing::{info, info_span, warn};

use super::super::Cli;

pub fn check_run_prerequisites(project_dir: &std::path::Path) -> Result<()> {
    use forge::init::{has_phases, is_initialized};

    if !is_initialized(project_dir) {
        anyhow::bail!(
            "Project not initialized. Run 'forge init' first, then 'forge generate' to create phases."
        );
    }
    if !has_phases(project_dir) {
        anyhow::bail!(
            "No phases found. Run 'forge generate' first to create phases from your spec."
        );
    }
    Ok(())
}

pub async fn run_orchestrator(
    cli: &Cli,
    project_dir: PathBuf,
    start_phase: Option<String>,
) -> Result<()> {
    use forge::audit::{AuditLogger, FileChangeSummary, PhaseAudit, PhaseOutcome, RunConfig};
    use forge::compaction::{
        CompactionManager, DEFAULT_MODEL_WINDOW_CHARS, extract_output_summary,
    };
    use forge::config::Config;
    use forge::forge_config::{ForgeToml, PermissionMode};
    use forge::gates::{
        ApprovalGate, AutonomousGateStrategy, GateDecision, IterationDecision, ProgressTracker,
    };
    use forge::hooks::{HookAction, HookManager};
    use forge::init::get_forge_dir;
    use forge::orchestrator::{ClaudeRunner, IterationFeedback, PromptContext, StateManager};
    use forge::phase::load_phases_or_default;
    use forge::tracker::GitTracker;
    use forge::ui::OrchestratorUI;

    check_run_prerequisites(&project_dir)?;

    let config = Config::new(
        project_dir.clone(),
        cli.verbose,

//! DAG executor for parallel phase execution with review integration.
//!
//! The executor runs phases in parallel while respecting dependencies and
//! integrating with the review system for quality gates.
//!
//! ## Scheduling Model
//!
//! Phases become ready as soon as **all of their specific predecessors** have
//! completed — the scheduler does not wait for all peers at the same dependency
//! level to finish before starting later phases.  Wave numbers are used only
//! for progress reporting; they do not impose a barrier.  The real concurrency
//! gate is the `max_parallel` semaphore, which limits how many phases may
//! execute simultaneously regardless of their position in the dependency graph.
//!
//! ## Cancellation Semantics
//!
//! When `fail_fast` is enabled and a phase fails, `active_tasks.drain()` aborts
//! **all currently in-flight tasks across any wave** — not just sibling tasks in
//! the current wave.  Every spawned `JoinHandle` that has not yet completed is
//! cancelled before the executor returns.

use crate::config::Config;
use crate::dag::scheduler::{DagConfig, DagScheduler};
use crate::dag::state::{DagState, DagSummary, ExecutionTimer, PhaseResult};
use crate::decomposition::{
    DecompositionConfig, DecompositionDetector, DecompositionExecutor, ExecutionSignals,
    parse_decomposition_output, parse_decomposition_request,
};
use crate::forge_config::ForgeToml;
use crate::init::get_forge_dir;

