1453→/// Execute a forge pipeline for the given issue, streaming stdout line by line.
1454→/// Uses `forge swarm` if phases.json exists, otherwise falls back to `claude --print`.
1455→/// Monitors output for progress JSON and emits PipelineProgress WS events.
1456→async fn execute_pipeline_streaming(
1457→    run_id: i64,
1458→    project_path: &str,
1459→    issue_title: &str,
1460→    issue_description: &str,
1461→    running_processes: &Arc<tokio::sync::Mutex<HashMap<i64, RunHandle>>>,
1462→    db: &DbHandle,
1463→    tx: &broadcast::Sender<String>,
1464→) -> Result<String> {
1465→    let mut cmd = build_execution_command(project_path, issue_title, issue_description);
1466→    let mut child = cmd.spawn().context("Failed to spawn pipeline process")?;
1467→
1468→    // Take stdout before storing child — we need ownership of the stdout handle
1469→    let stdout = child
1470→        .stdout
1471→        .take()
1472→        .context("Failed to capture stdout from child process")?;
1473→
1474→    // Store the child handle for cancellation
1475→    {
1476→        let mut processes = running_processes.lock().await;
1477→        processes.insert(run_id, RunHandle::Process(child));
1478→    }
1479→
1480→    // Read stdout line by line, looking for progress updates
1481→    let reader = BufReader::new(stdout);
1482→    let mut lines = reader.lines();
1483→    let mut all_output = String::new();
1484→    let mut last_output_broadcast = std::time::Instant::now() - std::time::Duration::from_secs(1);
1485→
1486→    while let Some(line) = lines
1487→        .next_line()
1488→        .await
1489→        .context("Failed to read stdout line")?
1490→    {
1491→        all_output.push_str(&line);
1492→        all_output.push('\n');
1493→
1494→        // Try to parse as DAG executor PhaseEvent first (from forge swarm)
1495→        if let Some(event) = try_parse_phase_event(&line) {
1496→            process_phase_event(&event, run_id, db, tx).await;
1497→            continue;
1498→        }
1499→
1500→        // Fall back to simple progress JSON (from claude --print)
1501→        if let Some(progress) = try_parse_progress(&line) {
1502→            // Update DB with progress
