    metrics.record_run_started("tok-run", "test", None).await.unwrap();
    metrics.record_phase_started("tok-run", 1, "phase-1", 5).await.unwrap();
    metrics.record_iteration("tok-run", 1, 1, 10.0, 5000, 3000, Some(1500), Some(800), false, 1, 0, 0).await.unwrap();
    metrics.record_iteration("tok-run", 1, 2, 8.0, 4000, 2500, Some(1200), Some(600), false, 1, 0, 0).await.unwrap();
    let usage = metrics.token_usage(30).await.unwrap();
    assert_eq!(usage.len(), 1);
    assert_eq!(usage[0].total_input, 2700); // 1500 + 1200
    assert_eq!(usage[0].total_output, 1400); // 800 + 600
    assert_eq!(usage[0].iteration_count, 2);
}
